/* jQuery 3.7 Minimal Subset — Finvanta CBS Offline Build */
/* Implements only the jQuery API surface used by finvanta-app.js and DataTables */
(function(global){
"use strict";
var jQuery = function(selector){
    if(typeof selector === 'function'){document.addEventListener('DOMContentLoaded',selector);return;}
    if(typeof selector === 'string'){
        var els = document.querySelectorAll(selector);
        var obj = Object.create(jQuery.fn);
        obj.length = els.length;
        for(var i=0;i<els.length;i++) obj[i]=els[i];
        return obj;
    }
    if(selector && selector.nodeType){
        var obj2 = Object.create(jQuery.fn);
        obj2[0]=selector;obj2.length=1;
        return obj2;
    }
    return Object.create(jQuery.fn);
};
jQuery.fn = {
    length:0,
    each:function(fn){for(var i=0;i<this.length;i++)fn.call(this[i],i,this[i]);return this;},
    on:function(evt,fn){this.each(function(){this.addEventListener(evt,fn);});return this;},
    ready:function(fn){document.addEventListener('DOMContentLoaded',fn);return this;},
    find:function(sel){var r=[];this.each(function(){var f=this.querySelectorAll(sel);for(var i=0;i<f.length;i++)r.push(f[i]);});var obj=Object.create(jQuery.fn);obj.length=r.length;for(var i=0;i<r.length;i++)obj[i]=r[i];return obj;},
    addClass:function(c){this.each(function(){this.classList.add(c);});return this;},
    removeClass:function(c){this.each(function(){this.classList.remove(c);});return this;},
    attr:function(k,v){if(v===undefined)return this[0]?this[0].getAttribute(k):undefined;this.each(function(){this.setAttribute(k,v);});return this;},
    val:function(v){if(v===undefined)return this[0]?this[0].value:undefined;this.each(function(){this.value=v;});return this;},
    text:function(v){if(v===undefined)return this[0]?this[0].textContent:'';this.each(function(){this.textContent=v;});return this;},
    html:function(v){if(v===undefined)return this[0]?this[0].innerHTML:'';this.each(function(){this.innerHTML=v;});return this;},
    append:function(h){this.each(function(){if(typeof h==='string')this.insertAdjacentHTML('beforeend',h);});return this;},
    css:function(k,v){this.each(function(){this.style[k]=v;});return this;},
    data:function(k){return this[0]?this[0].dataset[k]:undefined;},
    trigger:function(evt){this.each(function(){this.dispatchEvent(new Event(evt));});return this;}
};
jQuery.fn.DataTable = null; // placeholder — set by datatables.min.js
jQuery.extend = function(target){for(var i=1;i<arguments.length;i++){var src=arguments[i];if(src)for(var k in src)if(src.hasOwnProperty(k))target[k]=src[k];}return target;};
jQuery.isPlainObject = function(o){return typeof o==='object'&&o!==null&&o.constructor===Object;};
jQuery.each = function(obj,fn){if(Array.isArray(obj))for(var i=0;i<obj.length;i++)fn(i,obj[i]);else for(var k in obj)if(obj.hasOwnProperty(k))fn(k,obj[k]);};
global.jQuery = global.$ = jQuery;
})(typeof window !== 'undefined' ? window : this);
